  "code": "const pollMs = 100;
const drawTimeMs = 900;
const cooldownMs = 200;
const hostileNames = new Set(['zombie', 'skeleton', 'husk', 'drowned', 'stray', 'spider', 'creeper', 'baby_zombie', 'slime', 'magma_cube']);
const arrowNames = new Set(['arrow', 'spectral_arrow', 'tipped_arrow']);

const findNearestHostile = function () {
  let nearest = null;
  let minDist = Infinity;
  for (const id in bot.entities) {
    const entity = bot.entities[id];
    if (!entity || !entity.isValid || entity.type === 'player' || entity.type === 'item') continue;
    if (entity.kind === 'Hostile mobs' || entity.type === 'hostile' || hostileNames.has(entity.name)) {
      const dist = bot.entity.position.distanceTo(entity.position);
      if (dist < minDist) {
        minDist = dist;
        nearest = entity;
      }
    }
  }
  return nearest;
};

const hasArrows = function () {
  return bot.inventory.items().some(function (item) { return arrowNames.has(item.name); });
};

if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is not in a states to kite.';
}

const bow = bot.inventory.items().find(function (item) { return item.name === 'bow'; });
if (!bow) {
  return '<NO ITEM>: Bow is required for kiting.';
}

if (!hasArrows()) {
  return '<NO ITEM>: Arrows are required for kiting.';
}

startBackgroundSkill(bot, 'kite_nearest_hostile', async function (token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);
  const startTime = Date.now();

  try {
    while (canContinueBotAction(bot, token)) {
      if (Date.now() - startTime > args.maxDurationMs) break;
      if (bot.health < args.minHealth) break;
      if (!hasArrows()) break;

      const target = findNearestHostile();
      if (!target) {
        if (!await waitForActiveMs(bot, token, 500, pollMs)) return;
        continue;
      }

      const dist = bot.entity.position.distanceTo(target.position);

      if (dist < args.preferredDistance) {
        const retreatDir = bot.entity.position.minus(target.position).normalize();
        const retreatPos = bot.entity.position.plus(retreatDir.scale(args.retreatStepBlocks));
        bot.pathfinder.setGoal(new goals.GoalNear(retreatPos.x, retreatPos.y, retreatPos.z, 1));

        let moveCount = 0;
        while (canContinueBotAction(bot, token) && moveCount < 15 && bot.pathfinder.isMoving()) {
          moveCount++;
          if (!await waitForActiveMs(bot, token, 100, pollMs)) return;
        }
      } else {
        bot.pathfinder.stop();
        await bot.equip(bow, 'hand');
        if (!await waitUntilWorldActive(bot, token, pollMs)) return;

        const aimPos = target.position.offset(0, (target.height || 1.8) * 0.8, 0);
        await bot.lookAt(aimPos, true);

        bot.activateItem();
        if (!await waitForActiveMs(bot, token, drawTimeMs, pollMs)) return;

        const targetNow = findNearestHostile();
        if (targetNow) {
           await bot.lookAt(targetNow.position.offset(0, (targetNow.height || 1.8) * 0.8, 0), true);
        }

        bot.deactivateItem();
        if (!await waitForActiveMs(bot, token, cooldownMs, pollMs)) return;
      }

      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
    }
  } finally {
    bot.pathfinder.stop();
    bot.deactivateItem();
  }
});

return '<STARTED>: Kiting hostiles with preferred distance ' + args.preferredDistance + '.';
"
}

