      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
      await bot.equip(bow, 'hand');

      const headPos = target.position.offset(0, (target.height || 1.8) * 0.8, 0);
      await bot.lookAt(headPos, true);

      bot.activateItem();
      currentlyUsing = true;

      if (!await waitForActiveMs(bot, token, args.holdDrawMs, pollMs)) return;

      if (!canContinueBotAction(bot, token)) return;
      const refireTarget = findNearestHostile();
      if (refireTarget && refireTarget.id === target.id) {
        const updatePos = refireTarget.position.offset(0, (refireTarget.height || 1.8) * 0.8, 0);
